        involves_dwhitfield = (
            "dwhitfield" in ch_name
            or "whitfield" in ch_name
            or (dwhitfield_id and dwhitfield_id in members)
        )
        if involves_dwhitfield:
            dm_channel_ids.append(ch_id)

    if not dm_channel_ids:
        return {"pass": False, "score": 0.0,
                "feedback": "No DM channel to @dwhitfield found in slack_data.json"}

    # Collect only messages in those DM channels referencing CASE-2026-00202
    candidate_texts = []
    for ch_id in dm_channel_ids:
        for msg in messages.get(ch_id, []):
            if not isinstance(msg, dict):
                continue
            text = msg.get("text", "")
            if not isinstance(text, str):
                continue
            tl = text.lower()
            if "2026-00202" not in tl and "00202" not in tl:
                continue
            candidate_texts.append((ch_id, text))

    if not candidate_texts:
        return {"pass": False, "score": 0.0,
                "feedback": "No message referencing CASE-2026-00202 found in DM channel to @dwhitfield"}

    for ch_id, text in candidate_texts:
        tl = text.lower()

        # Condition 1: administrative denial nature identified
        has_admin = (
            "administrative" in tl
            or "prior auth" in tl
            or "prior authorization" in tl
            or "expired" in tl
            or "7.2.1" in tl
            or "no clinical" in tl
        )

        # Condition 2: disputed amount ($38,400) mentioned
        has_amount = "38,400" in tl or "38400" in tl

        # Condition 3: authority limit cited explicitly (not just bare "supervisor")
        has_authority = (
            "25,000" in tl
            or "25000" in tl
            or "coordinator authority" in tl
            or "authority limit" in tl
            or "co-sign" in tl
            or "cosign" in tl
            or "co-signature" in tl
            or "supervisor co" in tl
            or "supervisor approval" in tl
        )

        # All three conditions required — no fallback
        if has_admin and has_amount and has_authority:
            return {"pass": True, "score": 1.0,
                    "feedback": f"Found qualifying B-2 in DM channel {ch_id}: "
                                f"references administrative denial (§7.2.1), "
                                f"$38,400 disputed amount, and authority limit/co-signature requirement"}

    samples = [t[:200] for _, t in candidate_texts[:2]]
    return {"pass": False, "score": 0.0,
            "feedback": f"Found {len(candidate_texts)} message(s) referencing CASE-2026-00202 in DM "
                        f"to @dwhitfield but did not satisfy all three required elements "
                        f"(administrative denial, $38,400 amount, authority limit). "
                        f"Samples: {samples}"}

