        display = udata.get("display_name", "").lower()
        real    = udata.get("real_name", "").lower()
        if any("whitfield" in s or "dwhitfield" in s for s in (name, display, real)):
            dwhitfield_id = uid
            break

    # Collect DM channels involving dwhitfield
    dm_channel_ids = []
    for ch_id, ch_info in channels.items():
        if not isinstance(ch_info, dict):
            continue
        is_channel = ch_info.get("is_channel", True)
        ch_name    = ch_info.get("name", "").lower()
        members    = ch_info.get("members", [])

        is_dm = (
            not is_channel
            or ch_info.get("is_im", False)
            or ch_info.get("is_mpim", False)
            or ch_name.startswith("dm")
        )
        if not is_dm:
            continue

        involves_dwhitfield = (
            "dwhitfield" in ch_name
            or "whitfield" in ch_name
            or (dwhitfield_id and dwhitfield_id in members)
        )
        if involves_dwhitfield:
            dm_channel_ids.append(ch_id)

    if not dm_channel_ids:
        return {"pass": False, "score": 0.0,
                "feedback": "No DM channel to @dwhitfield found in slack_data.json"}

    # Search DM messages for the five required elements
    best_score = 0
    best_excerpt = ""
    best_missing = []

    for ch_id in dm_channel_ids:
