            text = msg.get("text", "")
            if not isinstance(text, str):
                continue
            tl = text.lower()

            # Element 1: Case ID
            has_case = bool(re.search(r"case[\-\s_]*2026[\-\s_]*00201", tl))

            # Element 2: Pre-Service type
            has_preservice = bool(re.search(r"pre[\-\s_]?service", tl))

