from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    slack_path = None
    for base in [external_services_path, workspace_path]:
        if base is None:
            continue
        candidate = Path(base) / "slack_data.json"
        if candidate.exists():
            slack_path = candidate
            break

    if slack_path is None:
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found."}

    try:
        with open(slack_path, "r", encoding="utf-8") as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read slack_data.json: {e}"}

    channels = data.get("channels", {})
    messages = data.get("messages", {})

    # Try to find #appeals-clinical-queue by channel name
    clinical_channel_id = None
    for ch_id, ch_info in channels.items():
        if isinstance(ch_info, dict) and "clinical" in ch_info.get("name", "").lower():
            clinical_channel_id = ch_id
            break

    # If channel metadata absent, search all message channels for clinical-queue content
    channels_to_search = []
    if clinical_channel_id:
        channels_to_search = [clinical_channel_id]
    else:
        channels_to_search = list(messages.keys())

    for ch_id in channels_to_search:
        for msg in messages.get(ch_id, []):
            if not isinstance(msg, dict):
                continue
            text = msg.get("text", "")
            if not isinstance(text, str):
                continue
            tl = text.lower()
            if ("2026-00196" in tl or "00196" in tl) and "pre-service" in tl and "medical" in tl and "2026-03-15" in tl:
                return {"pass": True, "score": 1.0,
                        "feedback": f"Found Format B-1 routing message for CASE-2026-00196 in channel {ch_id}"}

    return {"pass": False, "score": 0.0,
            "feedback": "No Format B-1 routing message for CASE-2026-00196 found in slack_data.json"}
